#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Create a hexi::static_buffer from the input span
    hexi::static_buffer<const uint8_t, buffer.size()> adaptor(buffer.data(), buffer.size());

    MessageHeader header;

    // Use the read() function to read the message_type and body_length into the MessageHeader struct
    adaptor.read(&header.message_type, sizeof(header.message_type));
    adaptor.read(&header.body_length, sizeof(header.body_length));

    // Use the skip() function to skip the body_data
    adaptor.skip(header.body_length);

    // Use the read() function to read the footer
    adaptor.read(&header.footer, sizeof(header.footer));

