    BufferData<> result;

    // Read the header value from the buffer using the read function
    buffer.read(&result.header, sizeof(result.header));

    // Create a vector to hold the data and read the data into the vector
    result.data.resize(data_length);
    if (data_length > 0) {
        buffer.read(result.data.data(), data_length);
    }

    return result;
}
