    std::vector<uint8_t> result;

    // Create a buffer adaptor for reading
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> read_adaptor(buffer);

    // Continue reading until buffer is empty
    while (read_adaptor.size() > 0) {
        // Determine how much to read (min of chunk_size and remaining data)
        std::size_t to_read = std::min(chunk_size, read_adaptor.size());

        // Read the data
        std::vector<uint8_t> temp(to_read);
        read_adaptor.read(temp.data(), to_read);

        // Append to result
        result.insert(result.end(), temp.begin(), temp.end());

        // Use size() to check remaining data after each read
        // Loop continues until size() becomes 0
    }

